    }
    
    class func isValidHost(_ path: String) -> Bool {
        // Allowlist valid hosts/paths
        let allowedPaths = ["reset-password"]
        return allowedPaths.contains(path.components(separatedBy: "/").first ?? "")
    }
    
    class func isValidToken(_ token: String) -> Bool {
        // Validate universal link parameters
        return !token.isEmpty && token.count == 6 // Assuming token is 6 characters long
    }
}

